     1|/**
     2| * IVX Autonomous Mode — the single 12-step lifecycle that lets IVX operate
     3| * without human babysitting, behind one entry point, composing the subsystems
     4| * that already exist:
     5| *
     6| *   1  receive task           — copy the owner task EXACTLY
     7| *   2  classify intent        — ivx-owner-execution-mode (+ the 6 safety gates)
     8| *   3  verify tools/access    — ivx-tool-availability
     9| *   4  create execution plan  — ivx-task-block-splitter
    10| *   5  execute                — ivx-self-heal-cycle (fix-and-verify loop)
    11| *   6  run tests              — self-heal test stage
    12| *   7  deploy if allowed      — derived from production verification + tools
    13| *   8  verify production      — ivx-production-guard (getProductionHealth)
    14| *   9  detect failure         — derived from steps 5–8
    15| *   10 retry or self-heal     — self-heal fix stage
    16| *   11 roll back if needed    — ivx-production-guard (triggerProductionRollback via self-heal)
    17| *   12 return proof           — ivx-execution-trace-store + evidence classification
    18| *
    19| * SAFETY GATES (human required) — a task is HELD for approval, never executed,
    20| * when its intent matches one of the six guarded categories:
    21| *   delete data · modify production schema · expose secrets · change billing /
    22| *   payment · disable security · grant external access.
    23| * (These map to the owner's list: destructive action / payment / credential
    24| * change / delete data / legal-compliance risk / production-rollback approval.)
    25| *
    26| * The heavy self-heal runner is INJECTABLE so this orchestrator is unit-testable
    27| * without the AI gateway / git / network. It never throws — every failure surfaces
    28| * as a failed step so the returned proof is always honest and complete.
    29| */
    30|import { classifyOwnerExecutionCommand, type IVXOwnerExecutionDecision } from './ivx-owner-execution-mode';
    31|import { checkToolAvailability, type ToolAvailabilityReport } from './ivx-tool-availability';
    32|import { splitTaskIntoBlocks, type IVXPlannedBlock } from './ivx-task-block-splitter';
    33|import type { SelfHealCycleReport } from './ivx-self-heal-cycle';
    34|import { getProductionHealth, type ProductionHealth } from './ivx-production-guard';
    35|import { recordExecutionTrace } from './ivx-execution-trace-store';
    36|import { EVIDENCE_CLASSIFICATION, type EvidenceClassification } from './ivx-evidence-gate';
    37|
    38|export const IVX_AUTONOMOUS_MODE_MARKER = 'ivx-autonomous-mode-2026-06-01';
    39|
    40|export type AutonomousStepStatus = 'verified' | 'failed' | 'skipped' | 'blocked' | 'unverified';
    41|
    42|export type AutonomousLifecycleStep = {
    43|  /** Ordinal 1..12 — matches the owner's requested lifecycle. */
    44|  step: number;
    45|  name: string;
    46|  status: AutonomousStepStatus;
    47|  /** Honest proof string for this step. */
    48|  proof: string;
    49|};
    50|
    51|export type AutonomousFinalStatus = 'VERIFIED' | 'FAILED' | 'BLOCKED_FOR_APPROVAL';
    52|
    53|export type AutonomousModeReport = {
    54|  marker: string;
    55|  taskId: string;
    56|  requestId: string;
    57|  startedAt: string;
    58|  finishedAt: string;
    59|  durationMs: number;
    60|  /** The owner task, copied exactly. */
    61|  task: string;
    62|  /** Step 2 — intent + safety-gate decision. */
    63|  intent: {
    64|    isOwnerExecutionCommand: boolean;
    65|    autoExecute: boolean;
    66|    requiresApproval: boolean;
    67|    approvalCategories: string[];
    68|    safeCategories: string[];
    69|    reason: string;
    70|  };
    71|  /** Step 3 — tool/access availability. */
    72|  toolAvailability: ToolAvailabilityReport;
    73|  /** Step 4 — execution plan. */
    74|  plan: { blockCount: number; blocks: { title: string }[] };
    75|  /** Steps 5–11 — the self-heal cycle result (null when blocked/skipped). */
    76|  selfHeal: SelfHealCycleReport | null;
    77|  /** Step 8 — production verification (null when not reached). */
    78|  production: ProductionHealth | null;
    79|  /** True when a human approval gate stopped execution. */
    80|  humanApprovalRequired: boolean;
    81|  /** Why a human is required (null when none). */
    82|  approvalReason: string | null;
    83|  /** The full ordered lifecycle ledger. */
    84|  steps: AutonomousLifecycleStep[];
    85|  /** Step 12 — owner-facing evidence classification. */
    86|  classification: EvidenceClassification;
    87|  finalStatus: AutonomousFinalStatus;
    88|  /** Step 12 — the durable execution-trace id linking this run's proof. */
    89|  executionTraceId: string | null;
    90|};
    91|
    92|export type RunAutonomousModeOptions = {
    93|  conversationId?: string | null;
    94|  approverEmail?: string;
    95|  /** Test suites the self-heal cycle should run (defaults to typecheck + lint). */
    96|  suites?: SelfHealCycleReport['tests'][number]['suite'][];
    97|  /** Injectable self-heal runner (defaults to the real cycle) — for testing. */
    98|  selfHealRunner?: (options: { approverEmail?: string }) => Promise<SelfHealCycleReport>;
    99|};
   100|
   101|function nowIso(): string {
   102|  return new Date().toISOString();
   103|}
   104|
   105|function genTaskId(): string {
   106|  if (typeof crypto !== 'undefined' && typeof crypto.randomUUID === 'function') {
   107|    return `autotask_${crypto.randomUUID()}`;
   108|  }
   109|  return `autotask_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 10)}`;
   110|}
   111|
   112|function genRequestId(): string {
   113|  if (typeof crypto !== 'undefined' && typeof crypto.randomUUID === 'function') {
   114|    return `autoreq_${crypto.randomUUID()}`;
   115|  }
   116|  return `autoreq_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 10)}`;
   117|}
   118|
   119|function step(n: number, name: string, status: AutonomousStepStatus, proof: string): AutonomousLifecycleStep {
   120|  return { step: n, name, status, proof };
   121|}
   122|
   123|/**
   124| * Run the full autonomous lifecycle for a single owner task.
   125| * Never throws — failures surface as failed steps and a FAILED final status.
   126| */
   127|export async function runAutonomousMode(
   128|  task: string,
   129|  options: RunAutonomousModeOptions = {},
   130|): Promise<AutonomousModeReport> {
   131|  const startedAt = nowIso();
   132|  const startMs = Date.now();
   133|  const taskId = genTaskId();
   134|  const requestId = genRequestId();
   135|  const steps: AutonomousLifecycleStep[] = [];
   136|  const exactTask = typeof task === 'string' ? task : String(task ?? '');
   137|
   138|  // ---- Step 1: receive task (copy exactly) ----
   139|  steps.push(step(
   140|    1,
   141|    'receive task',
   142|    exactTask.trim().length > 0 ? 'verified' : 'failed',
   143|    exactTask.trim().length > 0
   144|      ? `Task received and copied exactly (${exactTask.length} chars).`
   145|      : 'Empty task — nothing to execute.',
   146|  ));
   147|
   148|  // ---- Step 2: classify intent (+ safety gates) ----
   149|  const decision: IVXOwnerExecutionDecision = classifyOwnerExecutionCommand(exactTask);
   150|  steps.push(step(
   151|    2,
   152|    'classify intent',
   153|    'verified',
   154|    decision.requiresApproval
   155|      ? `Guarded intent: ${decision.approvalCategories.join(', ')} — human approval required.`
   156|      : `Intent: ${decision.isOwnerExecutionCommand ? 'execution command' : 'non-command'}; autoExecute=${decision.autoExecute}. ${decision.reason}`,
   157|  ));
   158|
   159|  // ---- Step 3: verify required tools/access ----
   160|  const toolAvailability = checkToolAvailability();
   161|  steps.push(step(
   162|    3,
   163|    'verify tools/access',
   164|    toolAvailability.canExecuteEndToEnd ? 'verified' : 'unverified',
   165|    `${toolAvailability.available}/${toolAvailability.total} tools available; end-to-end=${toolAvailability.canExecuteEndToEnd}${
   166|      toolAvailability.blockedSteps.length > 0 ? `; blocked steps: ${toolAvailability.blockedSteps.join(', ')}` : ''
   167|    }.`,
   168|  ));
   169|
   170|  // ---- Step 4: create execution plan ----
   171|  const blocks: IVXPlannedBlock[] = splitTaskIntoBlocks(exactTask);
   172|  steps.push(step(
   173|    4,
   174|    'create execution plan',
   175|    blocks.length > 0 ? 'verified' : 'failed',
   176|    `Plan: ${blocks.length} block(s) — ${blocks.slice(0, 5).map((b) => b.title).join(' · ')}${blocks.length > 5 ? ' …' : ''}.`,
   177|  ));
   178|
   179|  // ---- SAFETY GATE: human required for the six guarded categories ----
   180|  if (decision.requiresApproval) {
   181|    const approvalReason = `Human approval required: ${decision.approvalCategories.join(', ')}. ${decision.reason}`;
   182|    for (const [n, name] of [
   183|      [5, 'execute'],
   184|      [6, 'run tests'],
   185|      [7, 'deploy if allowed'],
   186|      [8, 'verify production'],
   187|      [9, 'detect failure'],
   188|      [10, 'retry or self-heal'],
   189|      [11, 'roll back if needed'],
   190|    ] as const) {
   191|      steps.push(step(n, name, 'blocked', `Held — ${approvalReason}`));
   192|    }
   193|    const traceId = await safeTrace({
   194|      taskId,
   195|      requestId,
   196|      conversationId: options.conversationId ?? null,
   197|      toolName: 'ivx-autonomous-mode',
   198|      rawOutput: { decision, blocks: blocks.map((b) => b.title) },
   199|      linkedClaim: `Autonomous task HELD for human approval (${decision.approvalCategories.join(', ')}).`,
   200|    });
   201|    steps.push(step(12, 'return proof', 'verified', `Held for approval; trace=${traceId ?? 'n/a'}.`));
   202|    return finalize({
   203|      taskId, requestId, startedAt, startMs, task: exactTask, decision, toolAvailability,
   204|      blocks, selfHeal: null, production: null, steps,
   205|      classification: EVIDENCE_CLASSIFICATION.NOT_EXECUTED,
   206|      finalStatus: 'BLOCKED_FOR_APPROVAL',
   207|      humanApprovalRequired: true, approvalReason, executionTraceId: traceId,
   208|    });
   209|  }
   210|
   211|  // ---- Steps 5–11: execute → test → deploy → verify → detect → retry → rollback ----
   212|  // Delegated to the self-heal cycle (find blocker → fix safely → test → verify
   213|  // production → rollback if needed → resume), which encodes exactly this loop.
   214|  let selfHeal: SelfHealCycleReport | null = null;
   215|  let production: ProductionHealth | null = null;
   216|  try {
   217|    // Lazy-import the heavy self-heal cycle (pulls the AI runtime) only when the
   218|    // default runner is actually used, so injected-runner callers/tests stay light.
   219|    const runner = options.selfHealRunner ?? (async (opts) => {
   220|      const { runSelfHealCycle } = await import('./ivx-self-heal-cycle');
   221|      return runSelfHealCycle({ approverEmail: opts.approverEmail, suites: options.suites });
   222|    });
   223|    selfHeal = await runner({ approverEmail: options.approverEmail });
   224|    production = selfHeal.production;
   225|
   226|    const fixStage = selfHeal.stages.find((s) => s.name === 'fix safely');
   227|    const testStages = selfHeal.stages.filter((s) => s.name.startsWith('run tests'));
   228|    const verifyStage = selfHeal.stages.find((s) => s.name === 'verify production');
   229|    const rollbackStage = selfHeal.stages.find((s) => s.name === 'rollback if needed');
   230|    const testsPassed = testStages.length > 0 && testStages.every((s) => s.status === 'verified');
   231|
   232|    steps.push(step(5, 'execute', fixStage ? mapStatus(fixStage.status) : 'skipped', fixStage?.proof ?? 'No execution stage produced.'));
   233|    steps.push(step(6, 'run tests', testStages.length > 0 ? (testsPassed ? 'verified' : 'failed') : 'skipped',
   234|      testStages.map((s) => s.proof).join(' | ') || 'No test suites run.'));
   235|    const directDeployAvailable = toolAvailability.tools.some((t) => (t.tool === 'render_deploy' || t.tool === 'github_write') && t.available);
   236|    steps.push(step(7, 'deploy if allowed',
   237|      // Direct API deploy → verified; otherwise SKIPPED, not failed: push-to-main
   238|      // auto-deploy (render.yaml autoDeployTrigger: commit) is still a valid path.
   239|      directDeployAvailable ? 'verified' : 'skipped',
   240|      directDeployAvailable
   241|        ? 'Deploy path available (direct GitHub/Render API control).'
   242|        : 'Direct deploy API not configured — ships via push-to-main auto-deploy (render.yaml autoDeployTrigger: commit).'));
   243|    steps.push(step(8, 'verify production', verifyStage ? mapStatus(verifyStage.status) : 'skipped', verifyStage?.proof ?? 'No production verification stage.'));
   244|
   245|    const anyFailure = selfHeal.stages.some((s) => s.status === 'failed') || !testsPassed || (production?.thresholdExceeded ?? false);
   246|    steps.push(step(9, 'detect failure', 'verified',
   247|      anyFailure ? 'Failure detected — see failed test/verify stages and production health.' : 'No failure detected across execute/test/verify.'));
   248|    steps.push(step(10, 'retry or self-heal', fixStage ? 'verified' : 'skipped',
   249|      fixStage ? `Self-heal repair proposal: ${fixStage.proof}` : 'No blocker required a fix proposal.'));
   250|    steps.push(step(11, 'roll back if needed', rollbackStage ? mapStatus(rollbackStage.status) : 'skipped', rollbackStage?.proof ?? 'No rollback stage.'));
   251|  } catch (error) {
   252|    const message = error instanceof Error ? error.message : String(error);
   253|    for (const [n, name] of [
   254|      [5, 'execute'], [6, 'run tests'], [7, 'deploy if allowed'], [8, 'verify production'],
   255|      [9, 'detect failure'], [10, 'retry or self-heal'], [11, 'roll back if needed'],
   256|    ] as const) {
   257|      steps.push(step(n, name, 'failed', `Self-heal cycle threw: ${message}`));
   258|    }
   259|  }
   260|
   261|  // ---- Step 12: return proof (durable execution trace + classification) ----
   262|  const executed = selfHeal !== null;
   263|  const allOk = executed
   264|    && steps.filter((s) => s.step >= 5 && s.step <= 11).every((s) => s.status === 'verified' || s.status === 'skipped');
   265|  const classification: EvidenceClassification = !executed
   266|    ? EVIDENCE_CLASSIFICATION.NOT_EXECUTED
   267|    : allOk
   268|      ? EVIDENCE_CLASSIFICATION.VERIFIED
   269|      : EVIDENCE_CLASSIFICATION.UNVERIFIED;
   270|  const finalStatus: AutonomousFinalStatus = classification === EVIDENCE_CLASSIFICATION.VERIFIED ? 'VERIFIED' : 'FAILED';
   271|
   272|  const traceId = await safeTrace({
   273|    taskId,
   274|    requestId,
   275|    conversationId: options.conversationId ?? null,
   276|    toolName: 'ivx-autonomous-mode',
   277|    rawOutput: {
   278|      decision,
   279|      toolAvailability: { available: toolAvailability.available, total: toolAvailability.total, canExecuteEndToEnd: toolAvailability.canExecuteEndToEnd },
   280|      selfHealCycleId: selfHeal?.cycleId ?? null,
   281|      steps,
   282|    },
   283|    rawOutputRef: selfHeal ? `logs/audit/self-heal/${selfHeal.cycleId}.json` : null,
   284|    linkedClaim: `Autonomous task ${finalStatus} (${classification}).`,
   285|  });
   286|  steps.push(step(12, 'return proof', 'verified',
   287|    `classification=${classification}; trace=${traceId ?? 'n/a'}; selfHealCycle=${selfHeal?.cycleId ?? 'n/a'}.`));
   288|
   289|  return finalize({
   290|    taskId, requestId, startedAt, startMs, task: exactTask, decision, toolAvailability,
   291|    blocks, selfHeal, production, steps, classification, finalStatus,
   292|    humanApprovalRequired: false, approvalReason: null, executionTraceId: traceId,
   293|  });
   294|}
   295|
   296|function mapStatus(s: SelfHealCycleReport['stages'][number]['status']): AutonomousStepStatus {
   297|  if (s === 'verified') return 'verified';
   298|  if (s === 'failed') return 'failed';
   299|  if (s === 'skipped') return 'skipped';
   300|  return 'unverified';
   301|}
   302|
   303|async function safeTrace(input: Parameters<typeof recordExecutionTrace>[0]): Promise<string | null> {
   304|  try {
   305|    return await recordExecutionTrace(input);
   306|  } catch {
   307|    return null;
   308|  }
   309|}
   310|
   311|function finalize(input: {
   312|  taskId: string;
   313|  requestId: string;
   314|  startedAt: string;
   315|  startMs: number;
   316|  task: string;
   317|  decision: IVXOwnerExecutionDecision;
   318|  toolAvailability: ToolAvailabilityReport;
   319|  blocks: IVXPlannedBlock[];
   320|  selfHeal: SelfHealCycleReport | null;
   321|  production: ProductionHealth | null;
   322|  steps: AutonomousLifecycleStep[];
   323|  classification: EvidenceClassification;
   324|  finalStatus: AutonomousFinalStatus;
   325|  humanApprovalRequired: boolean;
   326|  approvalReason: string | null;
   327|  executionTraceId: string | null;
   328|}): AutonomousModeReport {
   329|  return {
   330|    marker: IVX_AUTONOMOUS_MODE_MARKER,
   331|    taskId: input.taskId,
   332|    requestId: input.requestId,
   333|    startedAt: input.startedAt,
   334|    finishedAt: nowIso(),
   335|    durationMs: Date.now() - input.startMs,
   336|    task: input.task,
   337|    intent: {
   338|      isOwnerExecutionCommand: input.decision.isOwnerExecutionCommand,
   339|      autoExecute: input.decision.autoExecute,
   340|      requiresApproval: input.decision.requiresApproval,
   341|      approvalCategories: input.decision.approvalCategories,
   342|      safeCategories: input.decision.safeCategories,
   343|      reason: input.decision.reason,
