   345|    toolAvailability: input.toolAvailability,
   346|    plan: { blockCount: input.blocks.length, blocks: input.blocks.map((b) => ({ title: b.title })) },
   347|    selfHeal: input.selfHeal,
   348|    production: input.production,
   349|    humanApprovalRequired: input.humanApprovalRequired,
   350|    approvalReason: input.approvalReason,
   351|    steps: input.steps,
   352|    classification: input.classification,
   353|    finalStatus: input.finalStatus,
