     1|/**
     2| * IVX Autonomous Core — unified status surface for the senior-developer agent.
     3| *
     4| * IVX has grown a fleet of autonomous subsystems (audit engine, repair jobs,
     5| * incident store, production guard, code index, test reporter, …). This module
     6| * does NOT re-implement them — it aggregates their real state into one coherent
     7| * dashboard mapped to the ten autonomous-core capabilities the owner asked for,
     8| * and reduces everything to six work-status buckets:
     9| *
    10| *   completed · pending · blocked · failed · verified · unverified
    11| *
    12| * Each capability reports whether it is `online` (backed by a real, wired
    13| * subsystem), `partial`, or `missing`, plus the concrete artifact backing it.
    14| * This keeps reporting honest: nothing is marked done unless a real subsystem
    15| * is behind it.
    16| */
    17|import { listAuditJobs, type IVXAuditJobRecord } from './ivx-audit-job-store';
    18|import { countByStatus, listAuditItemSets, type AuditItemStatus } from './ivx-audit-item-store';
    19|import { getCodeIndexSummary, type CodeIndexSummary } from './ivx-code-index';
    20|import { getCodeGraphSummary, type CodeGraphSummary } from './ivx-code-graph';
    21|import { getContinuousSession, type ContinuousSession } from './ivx-continuous-execution';
    22|import { listIncidents } from './ivx-incident-store';
    23|import { getPrioritySummary, type PrioritySummary } from './ivx-priority-engine';
    24|import { listRepairJobs } from './ivx-repair-jobs';
    25|
    26|export const IVX_AUTONOMOUS_CORE_MARKER = 'ivx-autonomous-core-2026-05-28';
    27|
    28|export type CapabilityState = 'online' | 'partial' | 'missing';
    29|
    30|export type CapabilityStatus = {
    31|  id: string;
    32|  title: string;
    33|  state: CapabilityState;
    34|  backedBy: string;
    35|  detail: string;
    36|};
    37|
    38|export type StatusBuckets = {
    39|  completed: number;
    40|  pending: number;
    41|  blocked: number;
    42|  failed: number;
    43|  verified: number;
    44|  unverified: number;
    45|};
    46|
    47|export type AutonomousDashboard = {
    48|  marker: string;
    49|  generatedAt: string;
    50|  environment: {
    51|    nodeEnv: string;
    52|    mode: 'production' | 'development';
    53|    productionBaseUrlConfigured: boolean;
    54|    databaseConfigured: boolean;
    55|    githubConfigured: boolean;
    56|    aiGatewayConfigured: boolean;
    57|  };
    58|  buckets: StatusBuckets;
    59|  priority: PrioritySummary;
    60|  capabilities: CapabilityStatus[];
    61|  subsystems: {
    62|    auditJobs: { total: number; active: number; completed: number; failed: number };
    63|    auditItemSets: { total: number; items: number };
    64|    repairJobs: { total: number; failed: number; awaitingApproval: number };
    65|    incidents: { total: number; open: number; resolved: number };
    66|    codeIndex: CodeIndexSummary;
    67|    codeGraph: CodeGraphSummary;
    68|    continuous: { status: ContinuousSession['status']; passesRun: number; lastReason: string | null; deadlineAt: string | null };
    69|  };
    70|};
    71|
    72|function emptyBuckets(): StatusBuckets {
    73|  return { completed: 0, pending: 0, blocked: 0, failed: 0, verified: 0, unverified: 0 };
    74|}
    75|
    76|function addBuckets(target: StatusBuckets, source: Partial<StatusBuckets>): void {
    77|  for (const key of Object.keys(target) as (keyof StatusBuckets)[]) {
    78|    target[key] += source[key] ?? 0;
    79|  }
    80|}
    81|
    82|/** Map a structured audit-item status onto a dashboard bucket. */
    83|function auditItemStatusToBucket(status: AuditItemStatus): keyof StatusBuckets | null {
    84|  switch (status) {
    85|    case 'verified': return 'verified';
    86|    case 'fixed': return 'completed';
    87|    case 'unverified': return 'unverified';
    88|    case 'blocked': return 'blocked';
    89|    case 'failed': return 'failed';
    90|    case 'pending':
    91|    case 'in_progress': return 'pending';
    92|    default: return null;
    93|  }
    94|}
    95|
    96|function auditJobToBucket(job: IVXAuditJobRecord): keyof StatusBuckets {
    97|  switch (job.status) {
    98|    case 'completed': return 'completed';
    99|    case 'failed': return 'failed';
   100|    case 'cancelled': return 'blocked';
   101|    case 'paused': return 'blocked';
   102|    case 'queued':
   103|    case 'running': return 'pending';
   104|    default: return 'pending';
   105|  }
   106|}
   107|
   108|function readEnvFlag(name: string): boolean {
   109|  return Boolean(process.env[name] && String(process.env[name]).trim().length > 0);
   110|}
   111|
   112|/** Aggregate every subsystem into one dashboard. Read-only; never mutates. */
   113|export async function buildAutonomousDashboard(): Promise<AutonomousDashboard> {
   114|  const [auditJobs, auditItemSets, codeIndex, codeGraph, continuous, priority] = await Promise.all([
   115|    listAuditJobs(100),
   116|    listAuditItemSets(100),
   117|    getCodeIndexSummary(),
   118|    getCodeGraphSummary(),
   119|    getContinuousSession(),
   120|    getPrioritySummary(),
   121|  ]);
   122|  const repairJobs = listRepairJobs(100);
   123|  const incidents = listIncidents(100);
   124|
   125|  const buckets = emptyBuckets();
   126|
   127|  // Audit jobs → buckets.
   128|  for (const job of auditJobs) {
   129|    buckets[auditJobToBucket(job)] += 1;
   130|  }
   131|
   132|  // Structured audit items → buckets (the richest signal of real work).
   133|  let totalItems = 0;
   134|  for (const set of auditItemSets) {
   135|    const counts = countByStatus(set);
   136|    totalItems += set.items.length;
   137|    for (const status of Object.keys(counts) as AuditItemStatus[]) {
   138|      const bucket = auditItemStatusToBucket(status);
   139|      if (bucket) {
